$(document).ready(function(){$("#UserName").focus();$("#UserName").change(function(){$.ajax({async:false,type:"post",dataType:"json",url:rootUri+"Login/UserName_Change",data:{userName:$("#UserName").val()},success:function(a){if(a.success=="ok"){$("#RememberMe").attr("checked","checked");$("#Password").val(a.password)}else if(a.success=="no"||a.success=="null"){$("#RememberMe").removeAttr("checked");$("#Password").val("")}else alert(a)},error:ErrorProcess})})});